"use client"
import Link from "next/link"
import { motion, AnimatePresence } from "framer-motion"
import { 
    FileText, PanelLeftClose, PanelLeftOpen, SearchIcon, 
    Plus, Star, Clock, Settings, Asterisk, ChevronDown 
} from "lucide-react"
import ConversationRow from "./ConversationRow"
import SearchModal from "./SearchModal"
import SettingsPopover from "./SettingsPopover"
import { cls } from "./utils"
import { useState, useEffect, useMemo } from "react"
import { UseChatStore, useUIStore } from "@/stores/chat-store" // Import cả 2 store

// Component Section nội bộ với kỹ thuật Grid Animation mượt mà
const Section = ({ title, icon, isOpen, onToggle, children, emptyText }) => (
    <div className="flex flex-col">
        <button
            onClick={onToggle}
            className="flex w-full items-center justify-between px-2 py-2 text-[11px] font-bold tracking-wider text-zinc-500 hover:text-zinc-900 dark:text-zinc-400 dark:hover:text-zinc-100 transition-colors"
        >
            <div className="flex items-center gap-2">
                {icon}
                <span>{title}</span>
            </div>
            <ChevronDown className={cls("h-3 w-3 transition-transform duration-300 ease-out", !isOpen && "-rotate-90")} />
        </button>

        <div className={cls(
            "grid transition-[grid-template-rows,opacity] duration-300 ease-in-out",
            isOpen ? "grid-rows-[1fr] opacity-100" : "grid-rows-[0fr] opacity-0"
        )}>
            <div className="overflow-hidden">
                <div className="space-y-0.5 px-1 pb-2">
                    {children}
                </div>
            </div>
        </div>
    </div>
);

export default function Sidebar({ open, onClose, query, setQuery, searchRef }) {
    const [showSearchModal, setShowSearchModal] = useState(false)
    const [mounted, setMounted] = useState(false)

    // --- 1. Lấy Logic Data từ ChatStore ---
    const { conversations, selectedId, setSelectedId, togglePin, createNewChat } = UseChatStore()

    // --- 2. Lấy Logic UI từ UIStore (Giúp đóng mở mượt vì không dính lưu trữ nặng) ---
    const { 
        sidebarCollapsed, setSidebarCollapsed, 
        collapsedComponent, setCollapsedComponent 
    } = useUIStore()

    useEffect(() => { setMounted(true) }, [])

    // --- 3. Tự lọc dữ liệu tại Sidebar (Selector pattern) ---
    const { pinned, recent } = useMemo(() => {
        const filtered = (conversations || []).filter(c => 
            (c?.title?.toLowerCase() || "").includes(query.toLowerCase())
        );
        return {
            pinned: filtered.filter(c => c.pinned).sort((a, b) => b.updatedAt.localeCompare(a.updatedAt)),
            recent: filtered.filter(c => !c.pinned).sort((a, b) => b.updatedAt.localeCompare(a.updatedAt)).slice(0, 15)
        };
    }, [conversations, query]);

    if (!mounted) return null

    // Mini Sidebar khi thu nhỏ
    if (sidebarCollapsed) {
        return (
            <motion.aside
                initial={{ width: 80 }}
                animate={{ width: 64 }}
                className="z-50 flex h-full shrink-0 flex-col border-r border-zinc-200/60 bg-white dark:border-zinc-800 dark:bg-zinc-900"
            >
                <div className="flex items-center justify-center border-b border-zinc-200/60 px-3 py-3 dark:border-zinc-800">
                    <button onClick={() => setSidebarCollapsed(false)} className="rounded-xl p-2 hover:bg-zinc-100 dark:hover:bg-zinc-800">
                        <PanelLeftOpen className="h-5 w-5" />
                    </button>
                </div>
                <div className="flex flex-1 flex-col items-center gap-4 pt-6">
                    <button onClick={() => createNewChat()} className="rounded-xl p-2.5 hover:bg-zinc-100 dark:hover:bg-zinc-800 transition-all active:scale-90"><Plus className="h-5 w-5" /></button>
                    <button onClick={() => setShowSearchModal(true)} className="rounded-xl p-2.5 hover:bg-zinc-100 dark:hover:bg-zinc-800"><SearchIcon className="h-5 w-5" /></button>
                    <Link href="/doc" className="rounded-xl p-2.5 hover:bg-zinc-100 dark:hover:bg-zinc-800"><FileText className="h-5 w-5" /></Link>
                </div>
                <div className="mt-auto flex flex-col items-center pb-4">
                    <SettingsPopover>
                        <button className="rounded-xl p-2.5 hover:bg-zinc-100 dark:hover:bg-zinc-800"><Settings className="h-5 w-5" /></button>
                    </SettingsPopover>
                </div>
            </motion.aside>
        )
    }

    return (
        <>
            <AnimatePresence>
                {open && (
                    <motion.div
                        initial={{ opacity: 0 }} animate={{ opacity: 0.5 }} exit={{ opacity: 0 }}
                        className="fixed inset-0 z-40 bg-black/60 md:hidden"
                        onClick={onClose}
                    />
                )}
            </AnimatePresence>

            <motion.aside
                initial={{ x: -20 }} animate={{ x: 0 }}
                className="z-50 flex h-full w-64 lg:w-72 shrink-0 flex-col border-r border-zinc-200/60 bg-white dark:border-zinc-800 dark:bg-zinc-900 fixed inset-y-0 left-0 md:static md:translate-x-0"
            >
                {/* Header Sidebar */}
                <div className="flex items-center gap-2 border-b border-zinc-200/60 px-4 py-3 dark:border-zinc-800">
                    <div className="flex items-center gap-2">
                        <div className="grid h-8 w-8 place-items-center rounded-xl bg-zinc-900 text-white dark:bg-white dark:text-zinc-900">
                            <Asterisk className="h-4 w-4" />
                        </div>
                        <div className="text-sm font-bold tracking-tight">AI Assistant</div>
                    </div>
                    <button onClick={() => setSidebarCollapsed(true)} className="ml-auto rounded-lg p-1.5 hover:bg-zinc-100 dark:hover:bg-zinc-800 transition-colors">
                        <PanelLeftClose className="h-4 w-4 text-zinc-500" />
                    </button>
                </div>

                {/* Search & Actions */}
                <div className="space-y-3 p-3">
                    <div className="relative">
                        <SearchIcon className="absolute left-3 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-zinc-400" />
                        <input
                            ref={searchRef} type="text" value={query} onChange={(e) => setQuery(e.target.value)}
                            placeholder="Search chats..."
                            className="w-full rounded-lg border border-zinc-200 bg-zinc-50/50 py-2 pl-9 pr-3 text-sm outline-none focus:border-zinc-400 dark:border-zinc-800 dark:bg-zinc-950/30"
                        />
                    </div>
                    <button
                        onClick={() => createNewChat()}
                        className="flex w-full items-center justify-center gap-2 rounded-lg bg-zinc-900 py-2 text-sm font-medium text-white hover:bg-zinc-800 dark:bg-white dark:text-zinc-900 dark:hover:bg-zinc-200 transition-all active:scale-[0.98]"
                    >
                        <Plus className="h-4 w-4" /> New Chat
                    </button>
                </div>

                {/* Danh sách Chat với hiệu ứng Smooth Collapse */}
                <nav className="flex-1 overflow-y-auto custom-scrollbar px-2 space-y-1">
                    <Section 
                        title="PINNED CHATS" 
                        icon={<Star className="h-3 w-3" />}
                        isOpen={collapsedComponent.pinned}
                        onToggle={() => setCollapsedComponent(s => ({ ...s, pinned: !s.pinned }))}
                    >
                        {pinned.length === 0 ? (
                            <div className="py-4 text-center text-[11px] text-zinc-400">No pinned chats</div>
                        ) : (
                            pinned.map(c => (
                                <ConversationRow key={c.id} data={c} active={c.id === selectedId} onSelect={() => setSelectedId(c.id)} onTogglePin={() => togglePin(c.id)} />
                            ))
                        )}
                    </Section>

                    <Section 
                        title="RECENT" 
                        icon={<Clock className="h-3 w-3" />}
                        isOpen={collapsedComponent.recent}
                        onToggle={() => setCollapsedComponent(s => ({ ...s, recent: !s.recent }))}
                    >
                        {recent.length === 0 ? (
                            <div className="py-4 text-center text-[11px] text-zinc-400">No recent history</div>
                        ) : (
                            recent.map(c => (
                                <ConversationRow key={c.id} data={c} active={c.id === selectedId} onSelect={() => setSelectedId(c.id)} onTogglePin={() => togglePin(c.id)} />
                            ))
                        )}
                    </Section>
                </nav>

                {/* User Profile Footer */}
                <div className="border-t border-zinc-200/60 p-3 dark:border-zinc-800">
                    <SettingsPopover>
                        <button className="flex w-full items-center gap-2 rounded-lg p-2 hover:bg-zinc-100 dark:hover:bg-zinc-800 transition-colors">
                            <div className="h-7 w-7 rounded-full bg-zinc-200 dark:bg-zinc-700 flex items-center justify-center text-[10px] font-bold">JD</div>
                            <div className="flex-1 text-left min-w-0">
                                <p className="truncate text-xs font-medium">John Doe</p>
                                <p className="truncate text-[10px] text-zinc-500">Pro plan</p>
                            </div>
                            <Settings className="h-3.5 w-3.5 text-zinc-400" />
                        </button>
                    </SettingsPopover>
                </div>
            </motion.aside>

            <SearchModal
                isOpen={showSearchModal} onClose={() => setShowSearchModal(false)}
                conversations={conversations} selectedId={selectedId}
                onSelect={setSelectedId} togglePin={togglePin} createNewChat={createNewChat}
            />
        </>
    )
}

"use client"
