import { create } from "zustand"
import { persist } from 'zustand/middleware'
import { INITIAL_CONVERSATIONS } from "@/components/mockData"

const sleep = (ms: number): Promise<void> => {
    return new Promise((resolve) => setTimeout(resolve, ms));
};

export interface Message {
    id: string;
    role: "user" | "assistant" | "system";
    content: string;
    createdAt: string;
    editedAt?: string;
}
export interface Conversation {
    id: string;
    title: string;
    updatedAt: string;
    messageCount: number;
    preview: string;
    pinned: boolean;
    messages: Message[];
}
export interface SidebarComponentState {
    pinned: boolean;
    recent: boolean;
}

// ==========================================
// STORE 1: QUẢN LÝ DATA CHAT (NẶNG)
// ==========================================
interface ChatStore {
    conversations: Conversation[]
    selectedId: string | null
    isThinking: boolean
    thinkingConvId: string | null

    setConversations: () => Promise<void>
    setSelectedId: (id: string | null) => void
    setThinkingConvId: (convId: string | null) => void
    setIsThinking: (thinking: boolean) => void
    togglePin: (id: string) => void
    createNewChat: () => Promise<void>
    sendMessage: (convId: string, content: string) => Promise<void>
    resendMessage: (convId: string, messageId: string) => Promise<void>
    pauseThinking: () => void
}

export const UseChatStore = create<ChatStore>()(
    persist(
        (set, get) => ({
            conversations: [],
            selectedId: null,
            isThinking: false,
            thinkingConvId: null,

            setConversations: async () => {
                await sleep(2000);
                set({ conversations: INITIAL_CONVERSATIONS() })
            },
            setSelectedId: (selectedId) => set({ selectedId }),
            setThinkingConvId: (thinkingConvId) => set({ thinkingConvId }),
            setIsThinking: (isThinking) => set({ isThinking }),

            createNewChat: async () => {
                const tempId = `temp-${Date.now()}`;
                const tempChat: Conversation = {
                    id: tempId,
                    title: "New Chat",
                    updatedAt: new Date().toISOString(),
                    messageCount: 0,
                    preview: "",
                    pinned: false,
                    messages: [],
                };

                set((state) => ({ conversations: [tempChat, ...(state.conversations || [])] }));
                try {
                    await sleep(500);
                    const Conv: Conversation = {
                        id: `chat-${Math.random().toString(36).slice(2)}`,
                        title: "New Chat",
                        updatedAt: new Date().toISOString(),
                        messageCount: 0,
                        preview: "Say hello to start...",
                        pinned: false,
                        messages: [],
                    };

                    set((state) => ({
                        conversations: state.conversations.map(c => c?.id === tempId ? Conv : c),
                        selectedId: Conv.id
                    }));
                } catch (error) {
                    set((state) => ({
                        conversations: state.conversations.filter(c => c?.id !== tempId)
                    }));
                }
            },

            sendMessage: async (convId, content) => {
                if (!content.trim()) return
                const now = new Date().toISOString()
                const userMsg: Message = { id: Math.random().toString(36).slice(2), role: "user", content, createdAt: now }
                set((state) => ({
                    conversations: state.conversations.map((c) => {
                        if (c?.id !== convId) return c;
                        const msgs = [...(c.messages || []), userMsg];
                        return {
                            ...c,
                            messages: msgs,
                            updatedAt: now,
                            messageCount: msgs.length,
                            preview: content.slice(0, 80),
                        };
                    }),
                    isThinking: true,
                    thinkingConvId: convId
                }));

                setTimeout(() => {
                    set({ isThinking: true, thinkingConvId: convId })
                    set((state) => ({
                        conversations: state.conversations.map((c) => {
                            if (c?.id !== convId) return c
                            const asstMsg: Message = {
                                id: Math.random().toString(36).slice(2),
                                role: "assistant",
                                content: `Got it — I'll help with that.`,
                                createdAt: new Date().toISOString(),
                            }
                            const msgs = [...(c.messages || []), asstMsg]
                            return {
                                ...c,
                                messages: msgs,
                                updatedAt: new Date().toISOString(),
                                messageCount: msgs.length,
                                preview: asstMsg.content.slice(0, 80),
                            }
                        }),
                        isThinking: false,
                        thinkingConvId: null
                    }))
                }, 2000)
            },
            resendMessage: async (convId, messageId) => {
                const state = get();
                const conv = state.conversations.find((c) => c?.id === convId);
                if (!conv) return;
                const msg = conv.messages.find((m) => m?.id === messageId)
                if (!msg) return;

                set((state) => ({
                    conversations: state.conversations.map((c) => {
                        if (c?.id !== convId) return c;
                        return {
                            ...c,
                            messages: c.messages.filter((m) => m?.id !== messageId),
                        };
                    }),
                }));
                await get().sendMessage(convId, msg.content);
            },
            pauseThinking: () => set({ isThinking: false, thinkingConvId: null }),
            togglePin: (id) => {
                set((state) => ({
                    conversations: state.conversations.map((c) => (c?.id === id ? { ...c, pinned: !c.pinned } : c))
                }))
            }
        }),
        {
            name: 'chat-storage', // Lưu data nặng vào file riêng
            partialize: (state) => ({
                conversations: state.conversations,
                selectedId: state.selectedId,
            })
        }
    )
)

