import React, { useEffect, useMemo, useRef, useState } from "react"
import { Calendar, LayoutGrid, MoreHorizontal } from "lucide-react"
import { LoadingScreen } from "@/components/loading-screen"
import Sidebar from "@/components/Sidebar"
import Header from "@/components/Header"
import ChatPane from "@/components/ChatPane"
import GhostIconButton from "@/components/GhostIconButton"
// Đổi đường dẫn này tới nơi bạn lưu file store
import { UseChatStore } from "@/store/chatStore" 

export default function AIAssistantUI() {
    // 1. Lấy state và action từ Zustand
    const {
        sidebarOpen,
        setSidebarOpen,
        conversations,
        selectedId,
        setSelectedId,
        collapsedComponent,
        setCollapsedComponent,
        sidebarCollapsed,
        setSidebarCollapsed, 
        isThinking,
        thinkingConvId,
        createNewChat,
        sendMessage,
        resendMessage,
        pauseThinking,
        togglePin
    } = UseChatStore()

    // 2. Local State
    const [isMounted, setIsMounted] = useState(false)
    const [query, setQuery] = useState("")
    const searchRef = useRef(null)
    const composerRef = useRef(null)

    // 3. Hydration Fix
    useEffect(() => {
        setIsMounted(true)
    }, [])

    // 4. Khởi tạo chat mới nếu danh sách trống
    useEffect(() => {
        if (isMounted && !selectedId && conversations.length === 0) {
            createNewChat()
        }
    }, [isMounted, selectedId, conversations.length, createNewChat])

    // 5. Lắng nghe phím tắt
    useEffect(() => {
        const onKey = (e) => {
            if ((e.metaKey || e.ctrlKey) && e.key.toLowerCase() === "n") {
                e.preventDefault()
                createNewChat()
            }
            if (!e.metaKey && !e.ctrlKey && e.key === "/") {
                const tag = document.activeElement?.tagName?.toLowerCase()
                if (tag !== "input" && tag !== "textarea") {
                    e.preventDefault()
                    searchRef.current?.focus()
                }
            }
            if (e.key === "Escape" && sidebarOpen) setSidebarOpen(false)
        }
        window.addEventListener("keydown", onKey)
        return () => window.removeEventListener("keydown", onKey)
    }, [sidebarOpen, createNewChat, setSidebarOpen])

    // 6. Tính toán danh sách (Lọc & Sắp xếp)
    const filtered = useMemo(() => {
        if (!query.trim()) return conversations
        const q = query.toLowerCase()
        return conversations.filter((c) => 
            c.title.toLowerCase().includes(q) || c.preview.toLowerCase().includes(q)
        )
    }, [conversations, query])

    const pinned = filtered.filter((c) => c.pinned).sort((a, b) => (a.updatedAt < b.updatedAt ? 1 : -1))
    const recent = filtered
        .filter((c) => !c.pinned)
        .sort((a, b) => (a.updatedAt < b.updatedAt ? 1 : -1))
        .slice(0, 10)

    const selected = conversations.find((c) => c.id === selectedId) || null

    // Ngăn chặn render lỗi trước khi hydration hoàn tất
    if (!isMounted) {
        return <LoadingScreen />
    }

    return (
        <div className="h-screen w-full bg-zinc-50 text-zinc-900 dark:bg-zinc-950 dark:text-zinc-100">
            {/* Mobile Header */}
            <div className="md:hidden sticky top-0 z-40 flex items-center gap-2 border-b border-zinc-200/60 bg-white/80 px-3 py-2 backdrop-blur dark:border-zinc-800 dark:bg-zinc-900/70">
                <div className="ml-1 flex items-center gap-2 text-sm font-semibold tracking-tight">
                    <span className="inline-flex h-4 w-4 items-center justify-center">✱</span> AI Assistant
                </div>

                <div className="ml-auto flex items-center gap-2">
                    <GhostIconButton label="Schedule">
                        <Calendar className="h-4 w-4" />
                    </GhostIconButton>
                    <GhostIconButton label="Apps">
                        <LayoutGrid className="h-4 w-4" />
                    </GhostIconButton>
                    <GhostIconButton label="More">
                        <MoreHorizontal className="h-4 w-4" />
                    </GhostIconButton>
                </div>
            </div>

            {/* Main Layout */}
            <div className="flex h-screen w-full">
                <Sidebar
                    open={sidebarOpen}
                    onClose={() => setSidebarOpen(false)}
                    collapsed={collapsedComponent}
                    setCollapsed={setCollapsedComponent}
                    sidebarCollapsed={sidebarCollapsed}
                    setSidebarCollapsed={setSidebarCollapsed}
                    conversations={conversations}
                    pinned={pinned}
                    recent={recent}
                    selectedId={selectedId}
                    onSelect={setSelectedId}
                    togglePin={togglePin}
                    query={query}
                    setQuery={setQuery}
                    searchRef={searchRef}
                    createNewChat={createNewChat}
                />

                <main className="relative flex min-w-0 flex-1 flex-col">
                    <Header 
                        createNewChat={createNewChat} 
                        sidebarCollapsed={sidebarCollapsed} 
                        setSidebarOpen={setSidebarOpen} 
